<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Kanban Board</title>
<style>
  * { box-sizing: border-box; }
  body {
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    background: #f4f5f7;
    margin: 0;
    padding: 30px;
    color: #172b4d;
  }
  h1 {
    margin-top: 0;
    font-size: 24px;
    color: #172b4d;
    margin-bottom: 20px;
  }
  .add-bar {
    display: flex;
    gap: 10px;
    margin-bottom: 24px;
    max-width: 940px;
  }
  #new-card {
    flex: 1;
    padding: 12px 14px;
    border: 1px solid #dfe1e6;
    border-radius: 6px;
    font-size: 15px;
    outline: none;
    transition: border-color 0.2s;
  }
  #new-card:focus {
    border-color: #0052cc;
  }
  #add-card {
    padding: 12px 20px;
    background: #0052cc;
    color: #fff;
    border: none;
    border-radius: 6px;
    font-size: 15px;
    font-weight: 500;
    cursor: pointer;
    transition: background 0.2s;
  }
  #add-card:hover {
    background: #0043a6;
  }
  .board {
    display: flex;
    gap: 20px;
    align-items: flex-start;
  }
  .column {
    background: #ebecf0;
    border-radius: 8px;
    width: 300px;
    display: flex;
    flex-direction: column;
    padding: 12px;
    min-height: 500px;
  }
  .col-header {
    font-weight: 600;
    font-size: 14px;
    margin-bottom: 12px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 4px 6px;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    color: #5e6c84;
  }
  .count {
    background: #dfe1e6;
    border-radius: 12px;
    padding: 2px 10px;
    font-size: 13px;
    font-weight: 600;
    color: #172b4d;
  }
  .card-container {
    flex: 1;
    display: flex;
    flex-direction: column;
    gap: 10px;
    min-height: 50px;
  }
  .card {
    background: #fff;
    border-radius: 6px;
    padding: 12px 14px;
    box-shadow: 0 1px 2px rgba(9,30,66,0.25);
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    cursor: grab;
    user-select: none;
    transition: box-shadow 0.2s;
  }
  .card:hover {
    box-shadow: 0 2px 4px rgba(9,30,66,0.3);
  }
  .card:active {
    cursor: grabbing;
  }
  .card-title {
    flex: 1;
    word-break: break-word;
    font-size: 14px;
    line-height: 1.4;
  }
  .card-del {
    background: transparent;
    border: none;
    color: #6b778c;
    cursor: pointer;
    font-size: 18px;
    line-height: 1;
    padding: 0 0 0 10px;
    margin-top: -2px;
  }
  .card-del:hover {
    color: #de350b;
  }
</style>
</head>
<body>
  <h1>Kanban Board</h1>
  <div class="add-bar">
    <input type="text" id="new-card" placeholder="Enter a task title...">
    <button id="add-card">Add Card</button>
  </div>
  <div class="board">
    <div class="column" id="col-todo">
      <div class="col-header">To Do <span class="count">0</span></div>
      <div class="card-container"></div>
    </div>
    <div class="column" id="col-doing">
      <div class="col-header">Doing <span class="count">0</span></div>
      <div class="card-container"></div>
    </div>
    <div class="column" id="col-done">
      <div class="col-header">Done <span class="count">0</span></div>
      <div class="card-container"></div>
    </div>
  </div>

  <script>
    const STORAGE_KEY = 'kanban-board-state-v1';
    let cards = [];
    try {
      cards = JSON.parse(localStorage.getItem(STORAGE_KEY)) || [];
    } catch (e) {
      cards = [];
    }

    const colMap = {
      'col-todo': 'todo',
      'col-doing': 'doing',
      'col-done': 'done'
    };

    function save() {
      try {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(cards));
      } catch (e) {
        console.warn('Could not save to localStorage', e);
      }
    }

    function render() {
      document.querySelectorAll('.card-container').forEach(c => c.innerHTML = '');

      const counts = { todo: 0, doing: 0, done: 0 };

      cards.forEach(card => {
        if (!counts.hasOwnProperty(card.column)) {
          card.column = 'todo';
        }
        counts[card.column]++;

        const container = document.querySelector(`#col-${card.column} .card-container`);
        if (!container) return;

        const cardEl = document.createElement('div');
        cardEl.className = 'card';
        cardEl.draggable = true;
        cardEl.dataset.id = card.id;

        const titleEl = document.createElement('div');
        titleEl.className = 'card-title';
        titleEl.textContent = card.title;

        const delBtn = document.createElement('button');
        delBtn.className = 'card-del';
        delBtn.textContent = '\u00D7';
        delBtn.title = 'Delete card';
        delBtn.addEventListener('click', (e) => {
          e.stopPropagation();
          cards = cards.filter(c => c.id !== card.id);
          save();
          render();
        });

        cardEl.appendChild(titleEl);
        cardEl.appendChild(delBtn);

        cardEl.addEventListener('dragstart', e => {
          e.dataTransfer.setData('text/plain', card.id);
          e.dataTransfer.effectAllowed = 'move';
        });

        container.appendChild(cardEl);
      });

      for (const [colId, colName] of Object.entries(colMap)) {
        const colEl = document.getElementById(colId);
        const countEl = colEl.querySelector('.count');
        if (countEl) countEl.textContent = counts[colName];
      }
    }

    document.getElementById('add-card').addEventListener('click', () => {
      const input = document.getElementById('new-card');
      const title = input.value.trim();
      if (!title) return;
      const id = 'card-' + Date.now() + '-' + Math.random().toString(36).substr(2, 9);
      cards.push({ id, title, column: 'todo' });
      save();
      render();
      input.value = '';
      input.focus();
    });

    document.getElementById('new-card').addEventListener('keypress', e => {
      if (e.key === 'Enter') {
        document.getElementById('add-card').click();
      }
    });

    Object.entries(colMap).forEach(([colId, colName]) => {
      const colEl = document.getElementById(colId);

      colEl.addEventListener('dragover', e => {
        e.preventDefault();
        e.dataTransfer.dropEffect = 'move';
      });

      colEl.addEventListener('drop', e => {
        e.preventDefault();
        const id = e.dataTransfer.getData('text/plain');
        if (!id) return;
        const card = cards.find(c => c.id === id);
        if (card) {
          card.column = colName;
          save();
          render();
        }
      });
    });

    render();
  </script>
</body>
</html>
